def merge_sorted(a, b):
    i = j = 0
    result = []

    # Merge elements while both lists have remaining elements
    while i < len(a) and j < len(b):
        if a[i] <= b[j]:
            result.append(a[i])
            i += 1
        else:
            result.append(b[j])
            j += 1

    # Add remaining elements from list a (if any)
    while i < len(a):
        result.append(a[i])
        i += 1

    # Add remaining elements from list b (if any)
    while j < len(b):
        result.append(b[j])
        j += 1

    return result

